export function resolveAvatar(avatar?: string): string {
  if (!avatar) return AVATAR_PRESETS[0].url;
  if (avatar.startsWith("preset:")) {
    const found = AVATAR_PRESETS.find((p) => p.key === avatar);
    return found ? found.url : AVATAR_PRESETS[0].url;
  }
  return avatar;
}
